// ── Utilitaires ────────────────────────────────────────────────────────────

export function getArdecheByMonth(month: number, year: number): ConcourArdeche[] {
  return CONCOURS_ARDECHE_2026.filter(c => {
    const d = new Date(c.date);
    return d.getMonth() + 1 === month && d.getFullYear() === year;
  });
}

export function getArdecheByCategorie(cat: string): ConcourArdeche[] {
  return CONCOURS_ARDECHE_2026.filter(c =>
    c.categorie.toLowerCase().includes(cat.toLowerCase())
  );
}

export function getArdecheByType(type: ConcourArdeche["type"]): ConcourArdeche[] {
  return CONCOURS_ARDECHE_2026.filter(c => c.type === type);
}
